<?php
 namespace WPAICG\Core\Providers; use WP_Error; if (!defined('ABSPATH')) { exit; } abstract class BaseProviderStrategy implements ProviderStrategyInterface { public function decode_json(string $json_string, string $context): array|WP_Error {if (trim($json_string) === '') { return []; } $decoded = json_decode($json_string, true); if (json_last_error() !== JSON_ERROR_NONE) { $error_message = sprintf(__('Failed to parse JSON response from %1$s. Error: %2$s', 'gpt3-ai-content-generator'), $context, json_last_error_msg()); return new WP_Error('json_decode_error', $error_message); } return is_array($decoded) ? $decoded : []; } public function format_model_list(array $raw_models, string $id_key = 'id', string $name_key = 'id'): array {$formatted = []; if (!is_array($raw_models)) { return []; } foreach ($raw_models as $model) { if (!is_array($model)) { continue; } $id = $model[$id_key] ?? null; if (!empty($id)) { $name = $model[$name_key] ?? $id; $formatted[] = [ 'id' => $id, 'name' => $name, 'status' => $model['status'] ?? null, 'version' => $model['version'] ?? null, ]; } } usort($formatted, fn ($a, $b) => strcasecmp($a['name'] ?? '', $b['name'] ?? '')); return $formatted; } public function format_headers_for_curl(array $headers): array { $result = []; foreach ($headers as $k => $v) { $result[] = $k . ': ' . $v; } return $result; } public function get_request_options(string $operation): array { return [ 'method' => 'POST', 'timeout' => ($operation === 'stream') ? 120 : 60, 'user-agent' => 'AIPKit/' . (defined('WPAICG_VERSION') ? WPAICG_VERSION : '1.0') . '; ' . get_bloginfo('url'), 'sslverify' => apply_filters('https_local_ssl_verify', true), ]; } public function build_http_error_data_with_retry_after($response, int $status_code): array { $error_data = ['status' => $status_code]; $retry_after_header = wp_remote_retrieve_header($response, 'retry-after'); if (is_array($retry_after_header)) { $retry_after_header = reset($retry_after_header); } if (is_numeric($retry_after_header)) { $error_data['retry_after'] = (int) ceil((float) $retry_after_header); } elseif (is_string($retry_after_header) && $retry_after_header !== '') { $retry_after_time = strtotime($retry_after_header); if ($retry_after_time !== false) { $error_data['retry_after'] = max(1, $retry_after_time - time()); } } return $error_data; } abstract public function build_api_url(string $operation, array $params): string|WP_Error; abstract public function get_api_headers(string $api_key, string $operation): array; abstract public function format_chat_payload(string $user_message, string $instructions, array $history, array $ai_params, string $model): array; abstract public function parse_chat_response(array $decoded_response, array $request_data): array|WP_Error; abstract public function parse_error_response($response_body, int $status_code): string; abstract public function get_models(array $api_params): array|WP_Error; abstract public function build_sse_payload(array $messages, $system_instruction, array $ai_params, string $model): array; abstract public function parse_sse_chunk(string $sse_chunk, string &$current_buffer): array; abstract public function generate_embeddings($input, array $api_params, array $options = []): array|WP_Error; } 